19: package org.apache.flink.streaming.api.windowing.assigners;
20: 
21: import org.apache.flink.annotation.PublicEvolving;
22: import org.apache.flink.api.common.ExecutionConfig;
23: import org.apache.flink.api.common.typeutils.TypeSerializer;
24: import org.apache.flink.streaming.api.windowing.triggers.EventTimeTrigger;
