154:         public int getLength() {
155:             return Long.BYTES + Long.BYTES;
156:         }
157: 
158:         @Override
159:         public void serialize(TimeWindow record, DataOutputView target) throws IOException {
160:             target.writeLong(record.start);
161:             target.writeLong(record.end);
162:         }
163: 
164:         @Override
165:         public TimeWindow deserialize(DataInputView source) throws IOException {
166:             long start = source.readLong();
167:             long end = source.readLong();
168:             return new TimeWindow(start, end);
169:         }
170: 
171:         @Override
172:         public TimeWindow deserialize(TimeWindow reuse, DataInputView source) throws IOException {
173:             return deserialize(source);
174:         }
175: 
176:         @Override
177:         public void copy(DataInputView source, DataOutputView target) throws IOException {
178:             target.writeLong(source.readLong());
179:             target.writeLong(source.readLong());
180:         }
181: 
