190:         @SuppressWarnings("WeakerAccess")
191:         public static final class TimeWindowSerializerSnapshot
192:                 extends SimpleTypeSerializerSnapshot<TimeWindow> {
193: 
194:             public TimeWindowSerializerSnapshot() {
195:                 super(Serializer::new);
196:             }
197:         }
198:     }
